args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>

SELECT ?recipientLabel ?languageLabel WHERE {
  {
    SELECT ?recipient WHERE {
      ?recipient p:P166/ps:P166 wd:Q916783 .
    }
    LIMIT 1
  }
  ?recipient wdt:P6886 ?language .
  ?recipient rdfs:label ?recipientLabel .
  ?language rdfs:label ?languageLabel .
  FILTER(LANG(?recipientLabel) = 'en')
  FILTER(LANG(?languageLabel) = 'en')
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT DISTINCT ?recipient WHERE {
  ?recipient wdt:P166 wd:Q916783 .
}
